// NewCreateDraftPayload builds a corpus service createDraft endpoint payload.
func NewCreateDraftPayload(body *CreateDraftRequestBody, sessionToken *string, projectSlugInput *string) *corpus.CreateDraftPayload {
	v := &corpus.CreateDraftPayload{
		FilePath:        *body.FilePath,
		Title:           body.Title,
		Content:         body.Content,
		OriginalContent: body.OriginalContent,
		Operation:       *body.Operation,
		Source:          body.Source,
		AuthorType:      body.AuthorType,
		AuthorUserID:    body.AuthorUserID,
		AgentName:       body.AgentName,
	}
	if body.Labels != nil {
		v.Labels = make([]string, len(body.Labels))
		for i, val := range body.Labels {
			v.Labels[i] = val
		}
	}
	v.SessionToken = sessionToken
	v.ProjectSlugInput = projectSlugInput

	return v
}

