func NewPublishDraftsPayload(body *PublishDraftsRequestBody, sessionToken *string, projectSlugInput *string) *corpus.PublishDraftsPayload {
	v := &corpus.PublishDraftsPayload{}
	v.DraftIds = make([]string, len(body.DraftIds))
	for i, val := range body.DraftIds {
		v.DraftIds[i] = val
	}
	v.SessionToken = sessionToken
	v.ProjectSlugInput = projectSlugInput

	return v
}

