// ValidateCreateDraftRequestBody runs the validations defined on
// CreateDraftRequestBody
func ValidateCreateDraftRequestBody(body *CreateDraftRequestBody) (err error) {
	if body.FilePath == nil {
		err = goa.MergeErrors(err, goa.MissingFieldError("file_path", "body"))
	}
	if body.Operation == nil {
		err = goa.MergeErrors(err, goa.MissingFieldError("operation", "body"))
	}
	if body.Operation != nil {
		if !(*body.Operation == "create" || *body.Operation == "update" || *body.Operation == "delete") {
			err = goa.MergeErrors(err, goa.InvalidEnumValueError("body.operation", *body.Operation, []any{"create", "update", "delete"}))
		}
	}
	return
}

